using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Tipo de efeito consumível pré-programado (Tarefa "Itens Consumíveis"):
/// define qual bloco de campos abaixo é relevante e qual sistema processa o
/// item ao ser usado (PlayerItemUser → EnemyStatusEffectReceiver para efeitos
/// em área sobre inimigos, ou PlayerConsumableEffects para efeitos no próprio
/// player). "Nenhum" mantém o comportamento legado (selfBuff / procura de
/// inimigo único).
/// </summary>
public enum ConsumableEffectType
{
    /// <summary>Sem efeito pré-programado (item genérico/legado).</summary>
    Nenhum,

    /// <summary>Flor do Silêncio — adormece inimigos numa área.</summary>
    Sono,

    /// <summary>Raiz de Aderência — buff próprio (reduz knockback/derrapagem). Usa os campos "Efeito Temporário no Player" existentes.</summary>
    Aderencia,

    /// <summary>Resina Antiga — imobiliza/afunda/derruba inimigos numa área, com comportamento por ambiente.</summary>
    Resina,

    /// <summary>Pó Dourado — torna o player invisível e faz inimigos próximos perderem o alvo.</summary>
    Invisibilidade,

    /// <summary>Cristal de Gelo — congela inimigos numa área.</summary>
    Congelamento,

    /// <summary>Casca Serenna — escudo que bloqueia o próximo golpe.</summary>
    Escudo,

    /// <summary>Orvalho Veloz — aumenta a velocidade do player temporariamente.</summary>
    Velocidade,

    /// <summary>Luz de Gaia — destaca coleccionáveis próximos.</summary>
    DestacarColecionaveis,

    /// <summary>Néctar Verde — regeneração rápida de corações ao longo do tempo.</summary>
    Regeneracao,

    /// <summary>Bolha de Coral — imunidade temporária a correntes de água.</summary>
    ImunidadeCorrente,

    /// <summary>Incenso do Vento — impulso vertical instantâneo.</summary>
    ImpulsoVertical,

    /// <summary>
    /// Cura instantânea: ao usar, recupera <see cref="ItemData.instantHealAmount"/>
    /// corações. Usado pela <b>Seiva Vital</b> (item de inventário, comprado em
    /// loja). O Broto de Vida é um DROP de chão que cura directamente via
    /// <see cref="BrotoDeVidaPickup"/> — NÃO vai para o inventário e NÃO é
    /// vendido em lojas (GDD linha 3601).
    /// </summary>
    CuraInstantanea,
}

/// <summary>
/// Tipo/escopo de um item (Item Creator simples — Etapa 4.1).
/// </summary>
public enum ItemType
{
    /// <summary>Item comum (ex: materiais, consumíveis genéricos).</summary>
    Comum,

    /// <summary>Item especial/único (normalmente "dropsOnlyOnce" + "savedAsCollected").</summary>
    Especial,

    /// <summary>Item global: funciona em qualquer mundo (ex: Flor do Silêncio).</summary>
    Global,

    /// <summary>Item regional: só relevante no mundo/região onde existe.</summary>
    Regional,

    /// <summary>Tesouro (Tarefa #35): item vendável, trocável por Sementes nas lojas (ver ShopData).</summary>
    Tesouro
}

/// <summary>
/// Define um item do jogo (Item Creator simples — Etapa 4.1): identidade,
/// apresentação e as flags mínimas para inimigos/drops/missões funcionarem.
/// Usado em condições ("item equipado/possuído", quantidade — Etapa 5.2),
/// ações ("Dar Item"/"Remover Item" — Etapa 5.3), drops de inimigos
/// (EnemyDropTable — Etapa 4.3) e interacções de inimigos com itens
/// (EnemyItemInteractionConfig — Etapa 1.1).
/// </summary>
[CreateAssetMenu(menuName = "Animals/Item Data", fileName = "NewItem")]
public class ItemData : ScriptableObject
{
    [Header("Identidade")]
    public string itemId;
    public string displayName;

    [Header("Apresentação")]
    [TextArea] public string description;
    public Sprite icon;

    [Header("Tipo (Etapa 4.1)")]
    public ItemType itemType = ItemType.Comum;

    [Header("Uso")]
    [Tooltip("O player pode usar este item activamente (ex: atirar, aplicar).")]
    public bool usableByPlayer = false;

    [Tooltip("O item gasta-se ao ser usado (remove 1 do inventário).")]
    public bool consumable = false;

    [Tooltip("Este item pode ser entregue a um NPC (ex: itens de missão/troca).")]
    public bool canBeDeliveredToNpc = false;

    [Tooltip("Este item pode aparecer como condição em diálogos (ex: \"tens uma Flor do Silêncio?\" — Condition_HasItemQuantity, Etapa 5.2).")]
    public bool canAppearInDialogueCondition = true;

    [Header("Comércio (Tarefa #35 — Sistema de Loja)")]
    [Tooltip("Pode ser vendido (ao vendedor, se a loja tiver 'merchantBuysItems' activo — ShopData.GetBuybackPrice usa 'sellPrice'). Itens Especiais que não devem poder ser vendidos devem deixar isto desligado.")]
    public bool sellable = false;

    [Tooltip("Preço de compra (Sementes) — preço-base a que as lojas vendem este item ao jogador (ShopEntry pode sobrepor com um preço próprio).")]
    [Min(0)] public int buyPrice = 0;

    [Tooltip("Preço de venda (Sementes) — valor-base do item; ao vender a um vendedor (recompra), o jogador recebe 'sellPrice' × ShopData.buybackMultiplier (por omissão, metade).")]
    [Min(0)] public int sellPrice = 0;

    [Tooltip("Se activo, este item só pode ser comprado UMA vez por save (ex: Jukebox). Após a compra, aparece no final da lista da loja com visual cinza/bloqueado. O estado é rastreado em PlayerProgress.collectedSpecialItemIds (usa 'itemId' como chave — requer 'savedAsCollected' também activo).")]
    public bool onlyBuyOnce = false;

    [Header("Inventário")]
    [Tooltip("Quantidade máxima deste item no inventário (respeitada por PlayerProgress.AddItem — Etapa 4.2).")]
    [Min(1)] public int maxQuantity = 1;

    [Header("Missões / Drops (Etapa 4)")]
    [Tooltip("É um item de missão (não deve ser vendido/descartado enquanto a missão estiver activa).")]
    public bool isMissionItem = false;

    [Tooltip("Este item só dropa UMA vez no jogo inteiro (drops únicos — EnemyDropTable, Etapa 4.3).")]
    public bool dropsOnlyOnce = false;

    [Tooltip("Ao ser recolhido, fica registado permanentemente como colectado (PlayerProgress.collectedSpecialItemIds — usado por 'dropsOnlyOnce' e por condições de diálogo, Etapa 5.2).")]
    public bool savedAsCollected = false;

    [Header("Efeito Temporário no Player (Tarefa #28 — ex: Raiz de Aderência)")]
    [Tooltip("Ao usar (usableByPlayer), aplica um buff temporário directamente ao player (knockback/derrapagem) em vez de procurar um inimigo alvo — ver PlayerCombat.ApplyTemporaryGripBuff.")]
    public bool selfBuff = false;

    [Tooltip("Duração do buff, em segundos (ex: Raiz de Aderência ~20s).")]
    [Min(0f)] public float selfBuffDuration = 20f;

    [Tooltip("Multiplicador de knockback recebido enquanto o buff estiver activo (1 = sem efeito, 0 = imunidade total a knockback).")]
    [Range(0f, 1f)] public float selfBuffKnockbackMultiplier = 1f;

    [Tooltip("Multiplicador de 'agarre' aplicado à derrapagem (skidBrake) enquanto o buff estiver activo (>= 1; quanto maior, menos derrapagem).")]
    [Min(1f)] public float selfBuffSkidGripMultiplier = 1f;

    // ==================================================================
    // Itens Consumíveis Pré-Programados (Casca Serenna, Orvalho Veloz,
    // Flor do Silêncio, Raiz de Aderência, Luz de Gaia, Resina Antiga,
    // Pó Dourado, Néctar Verde, Cristal de Gelo, Bolha de Coral, Incenso
    // do Vento). O ItemDataEditor mostra apenas os campos relevantes para
    // o "effectType" escolhido.
    // ==================================================================

    [Header("Efeito Consumível")]
    [Tooltip("Tipo de efeito pré-programado aplicado ao usar este item. 'Aderência' usa os campos de 'Efeito Temporário no Player' acima (Raiz de Aderência). Os outros tipos usam os campos abaixo.")]
    public ConsumableEffectType effectType = ConsumableEffectType.Nenhum;

    [Header("Alcance (efeitos em área — Sono, Resina, Congelamento, Invisibilidade)")]
    [Tooltip("Raio (em torno do player) afectado por este item. <= 0 usa o raio por defeito definido em PlayerItemUser.useRadius.")]
    [Min(0f)] public float effectRadius = 0f;

    [Tooltip("Afecta todos os alvos dentro do raio (em vez de só o mais próximo). Recomendado para itens 'lançados ao ar' como Flor do Silêncio, Resina Antiga, Pó Dourado e Cristal de Gelo.")]
    public bool affectAllInRadius = true;

    [Header("Sono (Flor do Silêncio)")]
    [Tooltip("Duração do sono dos inimigos afectados, em segundos. <= 0 usa a duração por defeito do inimigo (EnemyStatusEffectReceiver.sleepDuration).")]
    [Min(0f)] public float sleepDuration = 4f;

    [Header("Resina Antiga")]
    [Tooltip("Duração do efeito de imobilização/raiz, em segundos. <= 0 usa a duração por defeito do inimigo (EnemyStatusEffectReceiver.trapDuration).")]
    [Min(0f)] public float resinDuration = 3f;

    [Tooltip("Inimigos voadores não-imunes são puxados para baixo a esta velocidade (unidades/seg) enquanto durar o efeito. 0 = sem puxão (apenas imobiliza no ar).")]
    [Min(0f)] public float resinFlyingPullSpeed = 2f;

    [Tooltip("Inimigos aquáticos não-imunes afundam a esta velocidade (unidades/seg) enquanto durar o efeito. 0 = sem afundamento (apenas imobiliza).")]
    [Min(0f)] public float resinAquaticSinkSpeed = 1f;

    [Header("Pó Dourado (Invisibilidade)")]
    [Tooltip("Duração da invisibilidade do player, em segundos: enquanto activa, inimigos (salvo configuração contrária) não detectam o player.")]
    [Min(0f)] public float invisibilityDuration = 3f;

    [Header("Cristal de Gelo")]
    [Tooltip("Duração do congelamento dos inimigos afectados, em segundos. <= 0 usa a duração por defeito do inimigo (EnemyStatusEffectReceiver.freezeDuration).")]
    [Min(0f)] public float freezeDuration = 3f;

    [Header("Escudo (Casca Serenna)")]
    [Tooltip("Duração máxima do escudo, em segundos: o escudo é consumido ao bloquear o PRIMEIRO golpe que causaria dano, ou ao expirar este tempo — o que ocorrer primeiro. 0 = sem limite de tempo (só expira ao bloquear um golpe).")]
    [Min(0f)] public float shieldMaxDuration = 30f;

    [Tooltip("Se activo, o escudo NÃO bloqueia 'mortes especiais' (dano com IgnoreDefense — ex: quedas em vazio, armadilhas instantâneas). Continua a bloquear dano de combate normal.")]
    public bool shieldIgnoresSpecialDeaths = true;

    [Header("Velocidade (Orvalho Veloz)")]
    [Tooltip("Multiplicador de velocidade aplicado enquanto o efeito durar (ex: 1.3 = +30%).")]
    [Min(1f)] public float speedBoostMultiplier = 1.3f;

    [Tooltip("Duração do aumento de velocidade, em segundos.")]
    [Min(0f)] public float speedBoostDuration = 10f;

    [Header("Luz de Gaia (Destacar Coleccionáveis)")]
    [Tooltip("Raio em torno do player onde os coleccionáveis são destacados.")]
    [Min(0f)] public float highlightRadius = 8f;

    [Tooltip("Duração do destaque, em segundos.")]
    [Min(0f)] public float highlightDuration = 6f;

    [Tooltip("Tipos de coleccionável destacados por este item. Vazio = todos os tipos.")]
    public List<PickupType> highlightedPickupTypes = new List<PickupType>
    {
        PickupType.RunaDeGaia, PickupType.FragmentoVital, PickupType.BrotoDeVida,
        PickupType.SussurroDaTerra, PickupType.Chest, PickupType.MissionReward,
    };

    [Tooltip("Cor do destaque (pulso aplicado ao sprite do coleccionável).")]
    public Color highlightColor = new Color(1f, 0.92f, 0.3f, 1f);

    [Header("Néctar Verde (Regeneração)")]
    [Tooltip("Total de corações recuperados durante o efeito.")]
    [Min(1)] public int regenHearts = 2;

    [Tooltip("Tempo total (segundos) para recuperar todos os corações. Intervalo entre cada coração = regenDuration / regenHearts.")]
    [Min(0.1f)] public float regenDuration = 4f;

    [Header("Bolha de Coral (Imunidade a Correntes)")]
    [Tooltip("Duração da imunidade a correntes de água, em segundos.")]
    [Min(0f)] public float currentImmunityDuration = 12f;

    [Header("Incenso do Vento (Impulso Vertical)")]
    [Tooltip("Velocidade vertical aplicada instantaneamente ao usar (unidades/seg).")]
    [Min(0f)] public float windBurstForce = 14f;

    [Tooltip("Altura adicional aproximada concedida pelo impulso (unidades) — usada apenas como referência para balancear windBurstForce; não limita activamente a altura.")]
    [Min(0f)] public float windBurstMaxHeight = 5f;

    [Header("Cura Instantânea (Seiva Vital — item de loja)")]
    [Tooltip("Corações recuperados ao usar este item (effectType = CuraInstantanea). " +
             "Deve ser usado pela Seiva Vital (GDD). " +
             "O Broto de Vida é um drop de chão (BrotoDeVidaPickup) — cura directamente, NÃO passa pelo inventário e NÃO deve ser vendido em lojas.")]
    [Min(1)] public int instantHealAmount = 1;

    [Header("Geral — Feedback do Efeito")]
    [Tooltip("Som tocado ao activar o efeito.")]
    public AudioClip effectActivateSfx;

    [Tooltip("Som tocado quando o efeito termina (naturalmente ou consumido — ex: escudo bloqueando um golpe).")]
    public AudioClip effectEndSfx;

    [Tooltip("Prefab de VFX instanciado como filho do player enquanto o efeito estiver activo (destruído automaticamente ao terminar). Opcional.")]
    public GameObject effectVfxPrefab;
}
